func solve(nums []int64) int64 {
    n := len(nums) - 1
    isPrime := sieve(n)
    var sumA, sumB int64
    for i := 0; i < len(nums); i++ {
        if isPrime[i] {
            sumA += nums[i]
        } else {
            sumB += nums[i]
        }
    }
    diff := sumA - sumB
    if diff < 0 {
        diff = -diff
    }
    return diff
}

func sieve(n int) []bool {
    if n < 2 {
        return make([]bool, n+1)
    }
    isPrime := make([]bool, n+1)
    for i := range isPrime {
        isPrime[i] = true
    }
    isPrime[0] = false
    isPrime[1] = false
    for i := 2; i*i <= n; i++ {
        if isPrime[i] {
            for j := i * i; j <= n; j += i {
                isPrime[j] = false
            }
        }
    }
    return isPrime
}
